prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?participantName ?participant ?choreo
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2b18c5f00a5a46159c6cb6a3e2bc79e9" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .
}
ORDER BY LCASE(STR(?participantName))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?choreo
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }

  FILTER(
    (BOUND(?normId) && STR(?normId) = "2b18c5f00a5a46159c6cb6a3e2bc79e9") ||
    (BOUND(?origId) && STR(?origId) = "2b18c5f00a5a46159c6cb6a3e2bc79e9")
  )

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?participantName ?participant ?choreo
WHERE {
  VALUES ?choreo { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3406c2ea_744f_4829_b96a_36cd98fa7c13> }

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
  OPTIONAL { ?participant bbo:name ?participantName . }
}
ORDER BY LCASE(STR(?participantName))
LIMIT 25
